function parseCsvLine(line) {
  const fields = [];
  let i = 0;

  while (i <= line.length) {
    if (line[i] === '"') {
      // Quoted field: consume until closing quote, unescape ""
      let field = '';
      i++; // skip opening quote
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++; // skip closing quote
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      // skip the comma separator (or we're at end)
      if (line[i] === ',') i++;
    } else {
      // Unquoted field: read up to next comma or end
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      if (line[i] === ',') i++;
    }

    // Stop only when we've consumed the whole string and added the last field
    if (i > line.length) break;
    if (i === line.length && line[line.length - 1] === ',') {
      // trailing comma means one more empty field
      fields.push('');
      break;
    }
    if (i === line.length) break;
  }

  return fields;
}

